type GridItem = {
  id: string;
  opacity: number;
  color: string;
};

type FooterLink = {
  name: string;
  href: string;
};

type FooterSection = {
  title: string;
  links: FooterLink[];
};

type FooterConfig = {
  companyName: string;
  description: string;
  sections: FooterSection[];
  legal: FooterLink[];
  certifications?: React.ReactNode;
};

const DEFAULT_FOOTER_CONFIG: FooterConfig = {
  companyName: "Company",
  description: "Building the future of software.",
  sections: [
    {
      title: "Product",
      links: [
        { name: "Features", href: "#" },
        { name: "Pricing", href: "#" },
        { name: "Changelog", href: "#" },
        { name: "Documentation", href: "#" },
      ],
    },
    {
      title: "Company",
      links: [
        { name: "About", href: "#" },
        { name: "Blog", href: "#" },
        { name: "Careers", href: "#" },
        { name: "Contact", href: "#" },
      ],
    },
    {
      title: "Legal",
      links: [
        { name: "Privacy", href: "#" },
        { name: "Terms", href: "#" },
        { name: "Security", href: "#" },
      ],
    },
  ],
  legal: [
    { name: "Privacy Policy", href: "#" },
    { name: "Terms of Service", href: "#" },
    { name: "Cookie Policy", href: "#" },
  ],
};

function FlickeringGrid({
  squareSize = 4,
  gridGap = 6,
  flickerChance = 0.3,
  color = "rgb(0, 0, 0)",
  width,
  height,
  className,
  maxOpacity = 0.3,
}: {
  squareSize?: number;
  gridGap?: number;
  flickerChance?: number;
  color?: string;
  width?: number;
  height?: number;
  className?: string;
  maxOpacity?: number;
}) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isInView, setIsInView] = useState(false);
  const animationRef = useRef<number | null>(null);

  const memoizedColor = useMemo(() => {
    return getRGBA(color);
  }, [color]);

  const setupCanvas = useCallback(
    (canvas: HTMLCanvasElement, width: number, height: number) => {
      const dpr = window.devicePixelRatio || 1;
      canvas.width = width * dpr;
      canvas.height = height * dpr;
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      const cols = Math.floor(width / (squareSize + gridGap));
      const rows = Math.floor(height / (squareSize + gridGap));

      const squares: GridItem[] = [];
      for (let i = 0; i < cols * rows; i++) {
        squares.push({
          id: `${i}`,
          opacity: Math.random() * maxOpacity,
          color: memoizedColor,
        });
      }
      return { cols, rows, squares };
    },
    [squareSize, gridGap, maxOpacity, memoizedColor],
  );

  const updateSquares = useCallback(
    (squares: GridItem[], deltaTime: number) => {
      squares.forEach((square) => {
        if (Math.random() < flickerChance * deltaTime) {
          square.opacity = Math.random() * maxOpacity;
        }
      });
    },
    [flickerChance, maxOpacity],
  );

  const drawGrid = useCallback(
    (
      ctx: CanvasRenderingContext2D,
      width: number,
      height: number,
      cols: number,
      rows: number,
      squares: GridItem[],
    ) => {
      const dpr = window.devicePixelRatio || 1;
      ctx.clearRect(0, 0, width * dpr, height * dpr);
      squares.forEach((square, index) => {
        const col = index % cols;
        const row = Math.floor(index / cols);
        const x = col * (squareSize + gridGap) * dpr;
        const y = row * (squareSize + gridGap) * dpr;
        ctx.fillStyle = colorWithOpacity(square.color, square.opacity);
        ctx.fillRect(x, y, squareSize * dpr, squareSize * dpr);
      });
    },
    [squareSize, gridGap],
  );

  useEffect(() => {
    const canvas = canvasRef.current;
    const container = containerRef.current;
    if (!canvas || !container) return;

    const observer = new IntersectionObserver(
      ([entry]) => {
        setIsInView(entry.isIntersecting);
      },
      { threshold: 0 },
    );
    observer.observe(canvas);
    return () => {
      observer.disconnect();
    };
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas || !isInView) return;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    const containerWidth = width || canvas.offsetWidth;
    const containerHeight = height || canvas.offsetHeight;

    const { cols, rows, squares } = setupCanvas(
      canvas,
      containerWidth,
      containerHeight,
    );
    let lastTime = 0;

    const animate = (time: number) => {
      if (!isInView) return;
      const deltaTime = (time - lastTime) / 1000;
      lastTime = time;
      updateSquares(squares, deltaTime);
      drawGrid(ctx, containerWidth, containerHeight, cols, rows, squares);
      animationRef.current = requestAnimationFrame(animate);
    };

    animationRef.current = requestAnimationFrame(animate);

    return () => {
      if (animationRef.current !== null) {
        cancelAnimationFrame(animationRef.current);
      }
    };
  }, [setupCanvas, updateSquares, drawGrid, isInView, width, height]);

  return (
    <div ref={containerRef} className={cn("h-full w-full", className)}>
      <canvas ref={canvasRef} className="pointer-events-none" />
    </div>
  );
}

export default function FlickeringFooter({
  config = DEFAULT_FOOTER_CONFIG,
}: {
  config?: FooterConfig;
}) {
  return (
    <footer className="relative w-full overflow-hidden bg-white dark:bg-zinc-950">
      <div className="relative">
        {/* Flickering grid background */}
        <div className="pointer-events-none absolute inset-0 z-0 opacity-40 dark:opacity-20">
          <FlickeringGrid
            color="var(--foreground)"
            maxOpacity={0.15}
            flickerChance={0.05}
            squareSize={3}
            gridGap={8}
          />
        </div>

        <div className="relative z-10 mx-auto max-w-7xl px-6 py-16 lg:px-8">
          {/* Top section */}
          <div className="mb-12 grid grid-cols-1 gap-8 lg:grid-cols-4">
            {/* Brand column */}
            <div className="lg:col-span-1">
              <div className="mb-4 flex items-center gap-2">
                <Icons.logo className="size-6" />
                <span className="text-sm font-semibold text-zinc-900 dark:text-zinc-100">
                  {config.companyName}
                </span>
              </div>
              <p className="text-sm leading-relaxed text-zinc-500 dark:text-zinc-400">
                {config.description}
              </p>
              {config.certifications && (
                <div className="mt-4">{config.certifications}</div>
              )}
            </div>

            {/* Links columns */}
            <div className="grid grid-cols-2 gap-8 lg:col-span-3 lg:grid-cols-3">
              {config.sections.map((section) => (
                <div key={section.title}>
                  <h3 className="mb-3 text-xs font-semibold uppercase tracking-wider text-zinc-900 dark:text-zinc-100">
                    {section.title}
                  </h3>
                  <ul className="space-y-2">
                    {section.links.map((link) => (
                      <li key={link.name}>
                        <Link
                          href={link.href}
                          className="group flex items-center gap-1 text-sm text-zinc-500 transition-colors hover:text-zinc-900 dark:text-zinc-400 dark:hover:text-zinc-100"
                        >
                          {link.name}
                          <ChevronRightIcon className="size-3 opacity-0 transition-all group-hover:translate-x-0.5 group-hover:opacity-100" />
                        </Link>
                      </li>
                    ))}
                  </ul>
                </div>
              ))}
            </div>
          </div>

          {/* Divider */}
          <div className="border-t border-zinc-200 pt-8 dark:border-zinc-800">
            <div className="flex flex-col items-start justify-between gap-4 sm:flex-row sm:items-center">
              <p className="text-xs text-zinc-400 dark:text-zinc-500">
                © {new Date().getFullYear()} {config.companyName}. All rights
                reserved.
              </p>
              <div className="flex flex-wrap gap-4">
                {config.legal.map((link) => (
                  <Link
                    key={link.name}
                    href={link.href}
                    className="text-xs text-zinc-400 transition-colors hover:text-zinc-700 dark:text-zinc-500 dark:hover:text-zinc-300"
                  >
                    {link.name}
                  </Link>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </footer>
  );
}
